import { useCallback, useEffect, useState } from 'react';

export type Theme = 'light' | 'dark';

/*
 * Theme state, written to `document.body.className` so the Gemini theme's
 * `.light` / `.dark` CSS (loaded in styles/lucuma-ui.scss) takes effect —
 * the same mechanism packages/ui drives from its theme atom.
 */
export function useTheme(initial: Theme = 'dark'): readonly [Theme, () => void] {
  const [theme, setTheme] = useState<Theme>(initial);

  useEffect(() => {
    document.body.className = theme;
  }, [theme]);

  const toggle = useCallback(() => {
    setTheme((t) => (t === 'dark' ? 'light' : 'dark'));
  }, []);

  return [theme, toggle];
}

src/auth/AuthGate.tsx.source:
import './AuthGate.css';

import { useSetAtom } from 'jotai';
import { Button } from 'primereact/button';
import type { JSX, ReactNode } from 'react';

import { odbTokenAtom, useCanAccessAdmin, useIsLoggedIn, useUser } from '@/components/atoms/auth';
import { Lock, SignIn, SignOut } from '@/components/Icons';

import * as sso from './ssoClient';
import { currentAccess } from './user';

/**
 * Gates the whole app on role: not signed in → the sign-in screen; signed in
 * below staff → access denied, showing the actual role; staff/admin → the app.
 * The gate is a UI courtesy — the ODB and SSO enforce the same requirement on
 * every admin operation server-side.
 */
export function AuthGate({ children }: { children: ReactNode }): JSX.Element {
  const user = useUser();
  const isLoggedIn = useIsLoggedIn();
  const canAccessAdmin = useCanAccessAdmin();
  const setToken = useSetAtom(odbTokenAtom);

  // Drop the local token first — that alone signs the app out — then end the
  // SSO session. If that call fails the cookie just expires on its own.
  const signOut = async (): Promise<void> => {
    setToken(null);
    try {
      await sso.logout();
    } catch {
      // Nothing actionable from the gate; the local sign-out already happened.
    }
  };

  if (!isLoggedIn) {
    return (
      <GateScreen icon={<SignIn className="gate-icon" />} title="GPP Admin">
        <p>
          The Admin interface is restricted to Gemini <strong>staff</strong> and <strong>admin</strong> users. Sign in
          with your ORCID to continue.
        </p>
        <div className="gate-actions">
          <Button
            label="Sign in with ORCID"
            icon={<SignIn />}
            onClick={() => (window.location.href = sso.signInUrl())}
          />
        </div>
      </GateScreen>
    );
  }

  if (!canAccessAdmin) {
    return (
      <GateScreen icon={<Lock className="gate-icon" />} title="Access denied">
        <p>
          The Admin interface is restricted to <strong>staff</strong> and <strong>admin</strong> users; you are signed
          in as <strong>{currentAccess(user).toUpperCase()}</strong>. An admin can grant a staff role from the Users
          view.
        </p>
        <div className="gate-actions">
          <Button label="Sign out" icon={<SignOut />} outlined onClick={() => void signOut()} />
        </div>
      </GateScreen>
    );
  }

  return <>{children}</>;
}

function GateScreen({ icon, title, children }: { icon: ReactNode; title: string; children: ReactNode }): JSX.Element {
  return (
    <div className="gate-screen">
      <div className="gate-card">
        {icon}
        <h1>{title}</h1>
        <div className="gate-body">{children}</div>
      </div>
    </div>
  );
}

src/auth/AuthSession.tsx.source:
import { useSetAtom } from 'jotai';
import { useEffect, useRef } from 'react';

import { odbTokenAtom, useOdbTokenValue, useTokenExp, useUser } from '@/components/atoms/auth';
import { useToast } from '@/components/toastContext';

import { EXPIRATION_ANTICIPATION_SECONDS } from './environments';
import * as sso from './ssoClient';

/**
 * Keeps the SSO session alive, following packages/ui's Authentication
 * component: a silent cookie refresh on mount (so a returning user is signed
 * in without clicking), a proactive refresh shortly before each token expires,
 * and a one-time auto-switch to the user's staff/admin role — the only roles
 * that can use this app, so landing on `pi` first would just show a denial.
 *
 * Renders nothing; mount once inside the Jotai provider.
 */
export function AuthSession(): null {
  const toast = useToast();
  const token = useOdbTokenValue();
  const user = useUser();
  const exp = useTokenExp();
  const setToken = useSetAtom(odbTokenAtom);
  // Guard so the role auto-switch happens once per token, not per render.
  const switchedFor = useRef<string | null>(null);

  // Silent bootstrap: with no live session, try the refresh-token cookie once.
  const isLoggedIn = user !== null && exp !== null && exp > new Date();
  useEffect(() => {
    if (isLoggedIn) return;
    const controller = new AbortController();
    void sso.refreshToken(controller.signal).then((fresh) => {
      if (fresh && !controller.signal.aborted) setToken(fresh);
    });
    return () => {
      controller.abort();
    };
  }, [isLoggedIn, setToken]);

  // Proactive refresh: check every second; refresh shortly before expiry.
  // Guard against overlapping attempts and back off after a failure so a
  // refresh that cannot succeed doesn't retry once per second.
  const expMs = exp?.getTime();
  useEffect(() => {
    if (expMs === undefined) return;
    const controller = new AbortController();
    let inFlight = false;
    let nextAttempt = 0;
    const id = window.setInterval(() => {
      const now = Date.now();
      if (inFlight || now < nextAttempt) return;
      if (expMs - EXPIRATION_ANTICIPATION_SECONDS * 1000 >= now) return;
      inFlight = true;
      void sso
        .refreshToken(controller.signal)
        .then((fresh) => {
          if (fresh && !controller.signal.aborted) setToken(fresh);
          else nextAttempt = Date.now() + 30_000;
        })
        .finally(() => {
          inFlight = false;
        });
    }, 1000);
    return () => {
      window.clearInterval(id);
      controller.abort();
    };
  }, [expMs, setToken]);

  // Auto-switch to a staff/admin role when the active role is lower.
  useEffect(() => {
    if (!token || user?.type !== 'standard') return;
    if (switchedFor.current === token) return;
    if (user.role.type === 'staff' || user.role.type === 'admin') return;
    const staffRole = user.otherRoles.find((r) => r.type === 'staff' || r.type === 'admin');
    if (staffRole) {
      switchedFor.current = token;
      sso
        .setRole(staffRole.id)
        .then(setToken)
        .catch((err: unknown) => {
          toast.error('Role switch failed', err instanceof Error ? err.message : String(err));
        });
    }
  }, [token, user, setToken, toast]);

  return null;
}

src/auth/environments.ts.source:
/*
 * Per-environment service endpoints, resolved from the hostname at runtime —
 * the resource-ui pattern (see its ApolloConfigs.ts). Dev-server hosts fall
 * through to the localhost entry, whose relative URIs are served by the Vite
 * proxies in vite.config.ts; deployed hosts resolve to their real services, so
 * no development endpoint can ever reach a production bundle.
 *
 * SSO is listed alongside the ODB because the Admin app talks to both: the
 * cookie-based auth flows (login redirect, token refresh, role switch) must
 * target SSO's absolute origin, and the Users view queries SSO's GraphQL.
 */

export interface Environment {
  readonly name: 'development' | 'staging' | 'production';
  readonly ssoUri: string;
  readonly odbUri: string;
  /** SSO's GraphQL endpoint (the Users view's roster + role mutations). */
  readonly ssoGraphqlUri: string;
}

const DEV: Environment = {
  name: 'development',
  ssoUri: 'https://sso-dev.gpp.lucuma.xyz',
  odbUri: 'https://lucuma-postgres-odb-dev.herokuapp.com/odb',
  ssoGraphqlUri: 'https://sso-dev.gpp.lucuma.xyz/graphql',
};

const STAGING: Environment = {
  name: 'staging',
  ssoUri: 'https://sso-test.gpp.gemini.edu',
  odbUri: 'https://lucuma-postgres-odb-staging.herokuapp.com/odb',
  ssoGraphqlUri: 'https://sso-test.gpp.gemini.edu/graphql',
};

const PRODUCTION: Environment = {
  name: 'production',
  ssoUri: 'https://sso.gpp.gemini.edu',
  odbUri: 'https://lucuma-postgres-odb-production.herokuapp.com/odb',
  ssoGraphqlUri: 'https://sso.gpp.gemini.edu/graphql',
};

const LOCAL_DEV: Environment = {
  name: 'development',
  ssoUri: DEV.ssoUri,
  // Vite proxies (vite.config.ts) — same-origin in dev, so no CORS.
  odbUri: '/odb',
  ssoGraphqlUri: '/sso-graphql',
};

const environments = {
  'admin-dev.lucuma.xyz': DEV,
  'admin-staging.lucuma.xyz': STAGING,
  'admin.gemini.edu': PRODUCTION,
  localhost: LOCAL_DEV,
} satisfies Record<string, Environment>;

/** The environment a hostname resolves to; unknown hosts (dev-server
 *  aliases, previews) fall through to the proxied local-dev entry. */
export function environmentFor(hostname: string): Environment {
  return environments[hostname as keyof typeof environments] ?? LOCAL_DEV;
}

export const CURRENT_ENV: Environment = environmentFor(window.location.hostname);

/** How many seconds before token expiry to proactively refresh. */
export const EXPIRATION_ANTICIPATION_SECONDS = 30;

src/auth/ssoClient.ts.source:
/*
 * SSO endpoint operations — the same flows packages/ui implements in
 * auth/hooks.ts, as plain async functions over the environment's SSO origin:
 *
 *   POST /api/v1/refresh-token   → fresh JWT (text body) from the session cookie
 *   POST /api/v1/auth-as-guest   → guest JWT
 *   GET  /auth/v1/stage1?state=  → ORCID login redirect
 *   GET  /auth/v1/set-role?role= → switch active role (then refresh)
 *   POST /api/v1/logout          → clear the session
 *
 * All cookie-based, so every call sends credentials. SSO scopes its session
 * cookie to its own domain — these flows complete on the deployed hosts and on
 * any *.lucuma.xyz dev alias, but not from bare localhost (see the README).
 *
 * refreshToken/guestLogin resolve null on failure (a missing session is the
 * normal signed-out state, not an error); setRole/logout throw instead, so
 * callers surface the failure to the user.
 */
import { CURRENT_ENV } from './environments';

/** Exchange the SSO session cookie for a fresh JWT. Returns the token, or
 *  null when there is no session (or SSO is unreachable). */
export async function refreshToken(signal?: AbortSignal): Promise<string | null> {
  try {
    const res = await fetch(new URL('/api/v1/refresh-token', CURRENT_ENV.ssoUri), {
      method: 'POST',
      credentials: 'include',
      signal: signal ?? null,
    });
    if (!res.ok) return null;
    const token = (await res.text()).trim();
    return token || null;
  } catch {
    return null;
  }
}

/** Guest token (no ORCID). A guest cannot pass the Admin role gate — offered
 *  so the gate can demonstrate the denial honestly rather than erroring. */
export async function guestLogin(): Promise<string | null> {
  try {
    const res = await fetch(new URL('/api/v1/auth-as-guest', CURRENT_ENV.ssoUri), {
      method: 'POST',
      credentials: 'include',
    });
    if (!res.ok) return null;
    const token = (await res.text()).trim();
    return token || null;
  } catch {
    return null;
  }
}

/** The ORCID sign-in URL; navigating here begins the login redirect. `state`
 *  is where SSO returns the browser after the round-trip. */
export function signInUrl(returnTo: string = window.location.href): string {
  const url = new URL('/auth/v1/stage1', CURRENT_ENV.ssoUri);
  url.searchParams.set('state', returnTo);
  return url.toString();
}

/** Switch to one of the user's other roles and return the fresh token.
 *  Throws when SSO rejects the switch or is unreachable. */
export async function setRole(roleId: string): Promise<string> {
  const url = new URL('/auth/v1/set-role', CURRENT_ENV.ssoUri);
  url.searchParams.set('role', roleId);
  const res = await fetch(url, { method: 'GET', credentials: 'include' });
  if (!res.ok) throw new Error(`SSO rejected the role switch (${String(res.status)}).`);
  const fresh = await refreshToken();
  if (!fresh) throw new Error('SSO accepted the role switch but returned no fresh token.');
  return fresh;
}

/** End the SSO session. Throws when SSO rejects the call or is unreachable —
 *  callers should clear the local token first, then report the failure (the
 *  session cookie survives until it expires on its own). */
export async function logout(): Promise<void> {
  const res = await fetch(new URL('/api/v1/logout', CURRENT_ENV.ssoUri), { method: 'POST', credentials: 'include' });
  if (!res.ok) throw new Error(`SSO logout failed (${String(res.status)}).`);
}

src/auth/user.ts.source:
/*
 * The signed-in user, decoded from the SSO JWT — the same shape as
 * packages/ui/src/auth/user.ts, extended with the role-comparison helpers the
 * Admin app gates on (mirroring lucuma-core's Access ordering).
 *
 * Role hierarchy (increasing power): guest < pi < ngo < staff < admin < service.
 * The Admin app requires staff or better; the Users view's role mutations
 * additionally require admin server-side.
 */

export type RoleAccess = 'guest' | 'pi' | 'ngo' | 'staff' | 'admin' | 'service';

const ACCESS_ORDER: Record<RoleAccess, number> = {
  guest: 0,
  pi: 1,
  ngo: 2,
  staff: 3,
  admin: 4,
  service: 5,
};

export interface StandardRole {
  readonly type: 'pi' | 'ngo' | 'staff' | 'admin';
  readonly id: string;
  /** Present only for NGO roles. */
  readonly partner?: string;
}

export interface OrcidProfile {
  readonly orcidId: string;
  readonly profile: {
    readonly givenName?: string;
    readonly familyName?: string;
    readonly creditName?: string;
    readonly primaryEmail?: string | null;
  };
}

export interface StandardUser {
  readonly type: 'standard';
  readonly id: string;
  readonly role: StandardRole;
  readonly otherRoles: readonly StandardRole[];
  readonly profile: OrcidProfile;
}

export interface GuestUser {
  readonly type: 'guest';
  readonly id: string;
}

export interface ServiceUser {
  readonly type: 'service';
  readonly id: string;
  readonly name: string;
}

export type User = StandardUser | GuestUser | ServiceUser;

/** The access level of the user's currently active role. */
export function currentAccess(user: User | null): RoleAccess {
  if (!user) return 'guest';
  switch (user.type) {
    case 'standard':
      return user.role.type;
    case 'service':
      return 'service';
    case 'guest':
      return 'guest';
  }
}

export function accessAtLeast(user: User | null, min: RoleAccess): boolean {
  return ACCESS_ORDER[currentAccess(user)] >= ACCESS_ORDER[min];
}

/** Whether the user may enter the Admin app at all (staff or better). */
export const canAccessAdmin = (u: User | null): boolean => accessAtLeast(u, 'staff');

/** Human-readable display name, matching packages/ui's displayName(). */
export function displayName(user: User | null): string {
  if (!user) return 'Not signed in';
  if (user.type === 'guest') return 'Guest User';
  if (user.type === 'service') return `Service User (${user.name})`;
  const p = user.profile.profile;
  if (p.creditName) return p.creditName;
  if (p.givenName && p.familyName) return `${p.givenName} ${p.familyName}`;
  if (p.familyName) return p.familyName;
  if (p.givenName) return p.givenName;
  return user.profile.orcidId;
}

