import './checkTables.css';

import { Column } from 'primereact/column';
import { DataTable } from 'primereact/datatable';
import { type JSX, useMemo } from 'react';

import { Spinner, TriangleExclamation } from '@/components/Icons';
import { type ConflictRow, type ConflictSource, matchConflicts, useConflictCandidates } from '@/gql/conflicts';
import { friendlyError } from '@/gql/errors';
import { formatModeType } from '@/gql/shared';

/**
 * "Potential Conflicts" table (sc-9243): active programs planning equivalent
 * observations — configuration requests, plus observations in active ToO
 * programs — with a similar observing mode within half the requested
 * configuration's field of view. The active-period and observing-mode filters
 * run in the ODB; the coordinate cone is computed here until the ODB grows
 * coordinate query filters (sc-9240), at which point it moves server-side.
 */
export function ConflictsTable({
  title,
  sources,
}: {
  readonly title: string;
  readonly sources: readonly ConflictSource[];
}): JSX.Element {
  const { candidates, loading, error } = useConflictCandidates(sources);
  const rows = useMemo(() => matchConflicts(sources, candidates), [sources, candidates]);

  return (
    <section className="check-section">
      <h3
        className="check-title"
        title="Planned observations in other active programs that would yield equivalent data (sc-9243): a similar observing mode within half the requested configuration's field of view. Covers configuration requests and, since ToO configurations carry no coordinates, the observations of active ToO programs."
      >
        {title}
        {loading && <Spinner spin className="check-spinner" />}
      </h3>
      {error && (
        <p className="check-error">
          <TriangleExclamation /> Conflict check failed: {friendlyError(error)}
        </p>
      )}
      <DataTable
        value={rows}
        dataKey="key"
        className="pl-striped-table"
        emptyMessage={loading ? 'Checking active programs…' : 'No conflicting plans found in other active programs.'}
      >
        <Column
          field="sourceId"
          header="ID"
          style={{ width: '6rem' }}
          headerTooltip="The selected request/observation this conflict applies to."
        />
        <Column
          field="label"
          header="ObsId"
          style={{ width: '14rem' }}
          headerTooltip="The conflicting plan: a configuration request (program reference + request id) or a ToO program's observation reference."
        />
        <Column
          field="status"
          header="Status"
          style={{ width: '7rem' }}
          headerTooltip="The conflicting request's status, or the ToO observation's workflow state."
        />
        <Column
          field="target"
          header="Target"
          headerTooltip="Target name where known — approved configurations carry only coordinates."
        />
        <Column
          header="RA"
          style={{ width: '7rem' }}
          body={(r: ConflictRow) => r.raDeg?.toFixed(5) ?? '—'}
          headerTooltip="Right ascension of the conflicting plan, degrees."
        />
        <Column
          header="Dec"
          style={{ width: '7rem' }}
          body={(r: ConflictRow) => r.decDeg?.toFixed(5) ?? '—'}
          headerTooltip="Declination of the conflicting plan, degrees."
        />
        <Column
          header="Sep"
          style={{ width: '5rem' }}
          headerTooltip="Angular separation from the requested coordinates."
          body={(r: ConflictRow) => `${r.sepArcsec.toFixed(1)}″`}
        />
        <Column header="Config" style={{ width: '10rem' }} body={(r: ConflictRow) => formatModeType(r.modeType)} />
      </DataTable>
    </section>
  );
}

src/components/DataSourceBadge.tsx.source:
import './DataSourceBadge.css';

import type { JSX } from 'react';

import { Circle, CircleDot, Spinner, TriangleExclamation } from '@/components/Icons';

/** Small status chip for a view's live query: loading, live, empty, or the
 *  error itself — the view never fakes data to cover a failure. */
export function DataSourceBadge({
  loading,
  error,
  empty,
}: {
  loading: boolean;
  /** Present when the query failed (expired token, access denied, …). */
  error?: string;
  /** True when the query succeeded but returned nothing for this token. */
  empty?: boolean;
}): JSX.Element {
  if (loading) {
    return (
      <span className="ds-badge ds-loading" title="Querying…">
        <Spinner spin /> Loading…
      </span>
    );
  }
  if (error !== undefined) {
    return (
      <span className="ds-badge ds-warn" title={error}>
        <TriangleExclamation /> {error}
      </span>
    );
  }
  if (empty) {
    return (
      <span className="ds-badge ds-empty" title="The query returned no rows your role can see.">
        <Circle /> No records for your role
      </span>
    );
  }
  return (
    <span className="ds-badge ds-live" title="Live data.">
      <CircleDot /> Live data
    </span>
  );
}

src/components/DuplicatesTable.tsx.source:
import './checkTables.css';

import { Column } from 'primereact/column';
import { DataTable } from 'primereact/datatable';
import { type JSX, useEffect, useRef, useState } from 'react';

import { Spinner, TriangleExclamation } from '@/components/Icons';
import { type DuplicateRow, type DuplicateSource, findDuplicates } from '@/lib/geminiArchive';

interface DuplicatesState {
  readonly rows: readonly DuplicateRow[];
  readonly loading: boolean;
  readonly error: string | null;
}

/** The last check's result, tagged with the key it answers. Loading is
 *  derived (result key ≠ current key), so the effect never sets state
 *  synchronously — only from the fetch callbacks. */
interface FetchedDuplicates {
  readonly forKey: string;
  readonly rows: readonly DuplicateRow[];
  readonly error: string | null;
}

const NOTHING_FETCHED: FetchedDuplicates = { forKey: '', rows: [], error: null };

/** Run the sc-9244 duplication check whenever the sources change. Aborts the
 *  in-flight archive queries when the selection moves on. This one stays a
 *  hand-rolled effect: the archive is a REST endpoint (jsonsummary), not
 *  GraphQL, so Apollo hooks don't apply. The fetch effect is keyed on each
 *  source's search inputs, so a re-mapped array with identical content
 *  doesn't refetch; the array itself is read through a ref. */
function useDuplicates(sources: readonly DuplicateSource[]): DuplicatesState {
  const [fetched, setFetched] = useState<FetchedDuplicates>(NOTHING_FETCHED);
  const sourcesRef = useRef(sources);
  useEffect(() => {
    sourcesRef.current = sources;
  });
  const key = sources.length === 0 ? '' : JSON.stringify(sources.map((s) => [s.id, s.raDeg, s.decDeg, s.modeType]));
  useEffect(() => {
    if (key === '') return;
    const controller = new AbortController();
    findDuplicates(sourcesRef.current, controller.signal)
      .then((rows) => setFetched({ forKey: key, rows, error: null }))
      .catch((err: unknown) => {
        if (controller.signal.aborted) return;
        setFetched({ forKey: key, rows: [], error: err instanceof Error ? err.message : String(err) });
      });
    return () => controller.abort();
  }, [key]);
  if (key === '') return { rows: [], loading: false, error: null };
  const current = fetched.forKey === key;
  return {
    rows: current ? fetched.rows : [],
    loading: !current,
    error: current ? fetched.error : null,
  };
}

/**
 * "Potential Duplicate Observations" table (sc-9244): archive data that would
 * duplicate the given observations / change requests, one row per archive
 * observation. P/# = files with QA=Pass / total files — visitor instruments
 * may not set QA, so P is advisory, not authoritative.
 */
export function DuplicatesTable({
  title,
  sources,
}: {
  readonly title: string;
  readonly sources: readonly DuplicateSource[];
}): JSX.Element {
  const { rows, loading, error } = useDuplicates(sources);

  const unsearchable = sources.filter((s) => s.raDeg === null || s.decDeg === null).length;

  return (
    <section className="check-section">
      <h3
        className="check-title"
        title="Existing archive data with a similar instrument configuration near the requested coordinates (sc-9244). Searched via archive.gemini.edu with a radius of half the configuration's field of view."
      >
        {title}
        {loading && <Spinner spin className="check-spinner" />}
