/*
 * View-model types for the Admin views: the shapes the tables and editors
 * render, produced by each view's mapper (cfp.ts, programs.ts, …) from the
 * codegen-typed ODB responses. Wire types come from codegen (src/gql/odb/gen);
 * these stay hand-modeled because they are UI domain shapes, not the schema.
 */
import type { Partner } from '@/gql/sso/roster';

import type {
  ConfigurationRequestStatus,
  GeminiCallForProposalsType,
  Instrument,
  ProposalStatus,
  ScienceBand,
  ScienceSubtype,
  ToOActivation,
} from './odb/gen/graphql';

// The schema enums the views model with — re-exported so feature code can
// import them alongside the view-model types they appear in.
export type { ConfigurationRequestStatus, Instrument, ProposalStatus, ScienceBand, ToOActivation };

/** Which Gemini telescope a request's instrument belongs to. A UI-derived
 *  notion (from the instrument, in changeRequests.ts), not the schema's
 *  `Site` enum (GN/GS) — none of our operations select a Site field, so
 *  codegen doesn't emit that type. */
export type Site = 'NORTH' | 'SOUTH';

// --- Calls for Proposals view (ODB CallForProposals) ---------------------

/** GeminiCallForProposalsType → display label. `satisfies` makes a new enum
 *  value a compile error here rather than a blank cell. */
export const CFP_TYPE_LABEL = {
  REGULAR_SEMESTER: 'Regular Semester',
  FAST_TURNAROUND: 'Fast Turnaround',
  LARGE_PROGRAM: 'Large Program',
  DIRECTORS_TIME: "Director's Time",
  POOR_WEATHER: 'Poor Weather',
  DEMO_SCIENCE: 'Demo Science',
  SYSTEM_VERIFICATION: 'System Verification',
} as const satisfies Record<GeminiCallForProposalsType, string>;

export type CfpType = GeminiCallForProposalsType;

/** RA/Dec window for one Gemini site. */
export interface SiteCoordinateLimits {
  readonly raStart: number; // hours, 0–24
  readonly raEnd: number;
  readonly decStart: number; // degrees, −90–90
  readonly decEnd: number;
}

/** A partner's participation in a call, with an optional deadline override. */
export interface CfpPartner {
  readonly partner: Partner;
  readonly deadlineOverride?: string; // ISO date; falls back to the CfP default
}

export interface CallForProposals {
  readonly id: string;
  readonly title: string;
  readonly type: CfpType;
  readonly semester: string; // e.g. "2027B"
  readonly activeStart: string; // ISO date
  readonly activeEnd: string;
  readonly active: boolean;
  readonly allowsNonPartnerPi: boolean;
  readonly proprietaryMonths: number;
  readonly defaultDeadline: string; // ISO date
  readonly north: SiteCoordinateLimits;
  readonly south: SiteCoordinateLimits;
  readonly instruments: readonly string[];
  readonly partners: readonly CfpPartner[];
}

/** ODB `Instrument` enum → display label. Keys are the complete enum
 *  (enforced by `satisfies`); models carry enum values and only the UI
 *  renders labels, so membership checks never depend on display formatting. */
export const INSTRUMENT_LABEL = {
  ACQ_CAM_NORTH: 'Acq Cam North',
  ACQ_CAM_SOUTH: 'Acq Cam South',
  ALOPEKE: 'Alopeke',
  FLAMINGOS2: 'Flamingos-2',
  GHOST: 'GHOST',
  GMOS_NORTH: 'GMOS-N',
  GMOS_SOUTH: 'GMOS-S',
  GNIRS: 'GNIRS',
  GPI: 'GPI',
  GSAOI: 'GSAOI',
  IGRINS2: 'IGRINS-2',
  MAROON_X: 'MAROON-X',
  NIRI: 'NIRI',
  SCORPIO: 'SCORPIO',
  VISITOR_NORTH: 'Visitor North',
  VISITOR_SOUTH: 'Visitor South',
  ZORRO: 'Zorro',
} as const satisfies Record<Instrument, string>;

/** Instruments offerable on a call, in checklist (label) order. */
export const INSTRUMENTS = (Object.keys(INSTRUMENT_LABEL) as readonly Instrument[])
  .slice()
  .sort((a, b) => INSTRUMENT_LABEL[a].localeCompare(INSTRUMENT_LABEL[b]));

// --- Programs view (ODB Program) ------------------------------------------

/** The two ScienceSubtypes the Admin class dropdown offers. */
export type ProgramClass = Extract<ScienceSubtype, 'QUEUE' | 'CLASSICAL'>;
export const PROGRAM_CLASSES: readonly ProgramClass[] = ['QUEUE', 'CLASSICAL'];
export const PROGRAM_CLASS_LABEL: Record<ProgramClass, string> = { QUEUE: 'Queue', CLASSICAL: 'Classical' };

export const BANDS: readonly ScienceBand[] = ['BAND1', 'BAND2', 'BAND3', 'BAND4'];
export const BAND_LABEL: Record<ScienceBand, string> = {
  BAND1: 'Band-1',
  BAND2: 'Band-2',
  BAND3: 'Band-3',
  BAND4: 'Band-4',
};

/** One cell of the time-awards grid: hours allocated to a partner in a band. */
export interface Allocation {
  readonly category: Partner;
  readonly scienceBand: ScienceBand;
  readonly hours: number;
}

export const TOO_STATUSES: readonly ToOActivation[] = ['NONE', 'STANDARD', 'RAPID'];
export const TOO_LABEL: Record<ToOActivation, string> = { NONE: 'None', STANDARD: 'Standard', RAPID: 'Rapid' };

/** A contact scientist: an SSO/ODB user holding a SUPPORT_* ProgramUser role.
 *  `programUserId` is set for contacts already on the program (used to remove
 *  them); `userId` for roster picks not yet linked (used to add them). */
export interface ContactScientist {
  readonly name: string;
  readonly userId?: string;
  readonly programUserId?: string;
}

export interface Program {
  readonly id: string; // internal ProgramId, e.g. "p-172"
  /** Program reference label ("G-2027B-1234-Q"); falls back to the id. */
  readonly reference: string;
  readonly name: string;
  readonly pi: string;
  /** Derived from the proposal type's GraphQL __typename (Queue vs Classical) —
   *  there is no separate "programClass" field in the ODB schema. Other
   *  proposal types (LargeProgram, FastTurnaround, …) aren't Queue/Classical;
   *  default them to QUEUE since the Admin form only offers those two. */
  readonly programClass: ProgramClass;
  /** Only Queue proposals carry ToOActivation; Classical/others have none. */
  readonly tooStatus: ToOActivation;
  /** Program users with role SUPPORT_PRIMARY/SUPPORT_SECONDARY — the real
   *  Gemini "contact scientist" roles. */
  readonly contactScientists: readonly ContactScientist[];
  /** Active date range (ISO). Every program has a start/end (the ODB's
   *  1901/2099 sentinels are shown blank), always editable as dates. */
  readonly activeStart: string;
  readonly activeEnd: string;
  readonly proprietaryMonths: number;
  /** Queue proposals only — ConsiderForBand3 is CONSIDER/DO_NOT_CONSIDER/UNSET
   *  in the ODB. True = CONSIDER, false = DO_NOT_CONSIDER or UNSET. */
  readonly considerForBand3: boolean;
  /** Queue/Classical minPercentTime — the minimum fraction of the award that
   *  must be observed for the program to count as successful. */
  readonly minPercentTime: number;
  readonly privateHeader: boolean;
  /** Names of program users (typically COIs) whose `thesis` flag is set — the
   *  ODB tracks thesis per investigator (ProgramUser.thesis), not per program. */
  readonly thesisInvestigators: readonly string[];
  readonly allocations: readonly Allocation[];
  /** The program's private note (Program.notes, isPrivate = true) — also
   *  visible to staff in Explore. `privateNoteId` is null when no private
   *  note exists yet (create vs update on save). */
  readonly privateNote: string;
  readonly privateNoteId: string | null;
}

// --- Proposals view (ODB Proposal, special types) --------------------------

/** The ScienceSubtypes the Admin "Proposals" view reviews (DD / Poor Weather). */
export type SpecialProposalType = Extract<ScienceSubtype, 'DIRECTORS_TIME' | 'POOR_WEATHER'>;

export const SPECIAL_PROPOSAL_TYPE_LABEL: Record<SpecialProposalType, string> = {
  DIRECTORS_TIME: "Director's Time",
  POOR_WEATHER: 'Poor Weather',
};

/** One observation row in a proposal/change-request detail table. */
export interface ObservationRow {
  readonly id: string;
  readonly target: string;
  /** RA "02:39:12" / Dec "+10:50:49"; "—" for non-sidereal targets. */
  readonly ra: string;
  readonly dec: string;
  /** Coordinates in degrees for the sc-9243/9244 checks; null for
   *  non-sidereal targets (nothing fixed to cone-search around). */
  readonly raDeg: number | null;
  readonly decDeg: number | null;
  /** ODB ObservingModeType ("GMOS_SOUTH_LONG_SLIT"), driving the checks'
   *  similar-instrument + mode search; null when mode-less. */
  readonly modeType: string | null;
  readonly instrument: string;
  /** Instrument + observing-mode summary, e.g. "GMOS-S, LongSlit". */
  readonly config: string;
  /** Compact conditions, e.g. "IQ<0.8″ / CC70 / SB80 / WV80". */
  readonly conditions: string;
  readonly hours: number;
}

export interface Proposal {
  readonly id: string;
  readonly reference: string; // e.g. "G-2027B-0123"
  /** Semester token from the reference ("2027B"); "—" when unreferenced. */
  readonly semester: string;
  readonly pi: string;
  readonly title: string;
  readonly type: SpecialProposalType;
  readonly status: ProposalStatus;
  readonly abstract: string;
  readonly observations: readonly ObservationRow[];
}

// --- Change Requests view (ODB ConfigurationRequest) ----------------------

export interface ChangeRequest {
  readonly id: string;
  readonly programId: string;
  /** Program reference label ("G-2027B-1234-Q"); falls back to the id. */
  readonly programReference: string;
  readonly programTitle: string;
  readonly pi: string;
  readonly status: ConfigurationRequestStatus;
  readonly justification: string;
  readonly site: Site;
  /** RA/Dec of the requested configuration's target, e.g. "06:08:31.9" / "-59:32:27". */
  readonly ra: string;
  readonly dec: string;
  /** Degrees for the sc-9243/9244 checks; null for ToO configurations,
   *  which carry no coordinates. */
  readonly raDeg: number | null;
  readonly decDeg: number | null;
  /** ODB ObservingModeType of the requested configuration. */
  readonly modeType: string | null;
  readonly instrument: string; // display label, e.g. "GMOS-S"
  readonly conditions: string; // e.g. "IQ70/CC70/SB80/WV80"
  readonly observationIds: readonly string[];
  readonly observations: readonly ObservationRow[];
}

/** Synthesized status for a program's group of change requests (sc-9094 mockup):
 *  Approved = all approved, Denied = all denied, Open = at least one undecided,
 *  Mixed = a mix of approved and denied with none left open. */
export type ProgramCrStatus = 'Approved' | 'Denied' | 'Open' | 'Mixed';

export interface ProgramWithChangeRequests {
  readonly programId: string;
  /** Program reference label ("G-2027B-1234-Q"); falls back to the id. */
  readonly programReference: string;
  readonly programTitle: string;
  readonly pi: string;
  readonly site: Site;
  readonly status: ProgramCrStatus;
  readonly requests: readonly ChangeRequest[];
}

src/lib/geminiArchive.ts.source:
/*
 * Observation Duplication Check (sc-9244): query the Gemini Observatory
 * Archive for existing data that would duplicate a requested observation, to
 * preserve proprietary periods and avoid wasting telescope time.
 *
 * The archive's jsonsummary REST API (https://archive.gemini.edu/help/api.html)
 * is searched per requested configuration by similar instrument + high-level
 * mode + cone around the target. The browser reaches it through the dev
 * server's /archive proxy (the archive sends no CORS headers).
 */
import type { ObservingModeType } from '@/gql/odb/gen/graphql';

/** The high-level archive "Mode" search facet — exact slits/gratings are
 *  deliberately ignored per sc-9244. */
export type ArchiveMode = 'IMAGING' | 'LS' | 'MOS' | 'IFS';

/** What to ask the archive for one requested configuration. */
export interface ArchiveSearchSpec {
  /** Archive instrument path segments. "GMOS" covers both GMOS-N and GMOS-S
   *  in one query; other similar pairs (GNIRS ~ Flamingos-2, Alopeke ~ Zorro,
   *  GHOST ~ MAROON-X) need one query each. */
  readonly instruments: readonly string[];
  readonly mode: ArchiveMode;
  /** Cone search radius: half the largest field-of-view dimension of the
   *  requested configuration, floored at 60″ (the radius in sc-9244's example
   *  query) so tiny-aperture instruments still tolerate pointing differences. */
  readonly radiusArcsec: number;
}

const MIN_RADIUS_ARCSEC = 60;

function spec(instruments: readonly string[], mode: ArchiveMode, largestFovArcsec: number): ArchiveSearchSpec {
  return { instruments, mode, radiusArcsec: Math.max(largestFovArcsec / 2, MIN_RADIUS_ARCSEC) };
}

/** ODB ObservingModeType → archive search, encoding sc-9244's similar-
 *  instrument pairs and each configuration's largest field-of-view dimension
 *  (GMOS 5.5′ field, F2 6.1′ circle, GNIRS 99″ slit, Alopeke/Zorro 60″
 *  wide-field, fibre-fed GHOST/MAROON-X well under the 60″ floor).
 *  VISITOR_* modes have no archive instrument name and can't be searched. */
const SEARCH_SPEC: Partial<Record<ObservingModeType, ArchiveSearchSpec>> = {
  GMOS_NORTH_IMAGING: spec(['GMOS'], 'IMAGING', 330),
  GMOS_SOUTH_IMAGING: spec(['GMOS'], 'IMAGING', 330),
  GMOS_NORTH_LONG_SLIT: spec(['GMOS'], 'LS', 330),
  GMOS_SOUTH_LONG_SLIT: spec(['GMOS'], 'LS', 330),
  FLAMINGOS_2_IMAGING: spec(['F2', 'GNIRS'], 'IMAGING', 366),
  FLAMINGOS_2_LONG_SLIT: spec(['F2', 'GNIRS'], 'LS', 366),
  GNIRS_LONG_SLIT: spec(['GNIRS', 'F2'], 'LS', 99),
  IGRINS_2_LONG_SLIT: spec(['IGRINS-2'], 'LS', 60),
  ALOPEKE_SPECKLE: spec(['Alopeke', 'Zorro'], 'IMAGING', 7),
  ALOPEKE_WIDE_FIELD: spec(['Alopeke', 'Zorro'], 'IMAGING', 60),
  ZORRO_SPECKLE: spec(['Zorro', 'Alopeke'], 'IMAGING', 7),
  ZORRO_WIDE_FIELD: spec(['Zorro', 'Alopeke'], 'IMAGING', 60),
  GHOST_IFU: spec(['GHOST', 'MAROON-X'], 'IFS', 2),
  MAROON_X: spec(['MAROON-X', 'GHOST'], 'IFS', 1),
};

/** The wire types carry `string` for observing modes; only keys of
 *  SEARCH_SPEC (a subset of ObservingModeType) are searchable. */
export function archiveSearchSpec(modeType: string | null): ArchiveSearchSpec | null {
  if (modeType === null || !Object.hasOwn(SEARCH_SPEC, modeType)) return null;
  return SEARCH_SPEC[modeType as ObservingModeType] ?? null;
}

/** The shared DISTANCE rule of sc-9243/sc-9244: half the configuration's
 *  largest field-of-view dimension, floored at 60″. Also used by the ODB
 *  conflict check (conflicts.ts), which applies it to modes the archive
 *  can't search (VISITOR_*). */
export function searchRadiusArcsec(modeType: string | null): number {
  return archiveSearchSpec(modeType)?.radiusArcsec ?? MIN_RADIUS_ARCSEC;
}

/** One jsonsummary URL (proxied). CANONICAL = latest file versions only;
 *  SCIENCE/RAW/OBJECT/notengineering/NotFail = on-sky raw science data. */
export function archiveQueryUrl(
  instrument: string,
  mode: ArchiveMode,
  raDeg: number,
  decDeg: number,
  radiusArcsec: number,
): string {
  return `/archive/jsonsummary/CANONICAL/SCIENCE/RAW/OBJECT/notengineering/NotFail/${instrument}/${mode}/ra=${raDeg}/dec=${decDeg}/SR=${radiusArcsec}`;
}

/** The jsonsummary fields we read (one entry per file). */
export interface ArchiveFile {
  readonly observation_id: string | null;
  readonly instrument: string | null;
  readonly object: string | null;
  readonly ra: number | null;
  readonly dec: number | null;
  readonly filter_name: string | null;
  readonly exposure_time: number | null;
  readonly disperser: string | null;
  readonly central_wavelength: number | null;
  readonly focal_plane_mask: string | null;
  readonly qa_state: string | null;
}

/** One row of the "Potential Duplicate Observations" table: one archive
 *  observation, aggregated over its files. */
export interface DuplicateRow {
  /** Row identity for the table: one archive observation can duplicate
   *  several selected sources, so the observation id alone is not unique. */
  readonly key: string;
  /** The requested observation / change request this duplicate matched. */
  readonly sourceId: string;
  readonly observationId: string;
  /** Files in this observation with QA = Pass. Visitor instruments may not
   *  set QA, so a low P over a high # is not by itself disqualifying. */
  readonly passCount: number;
  readonly fileCount: number;
  readonly target: string;
  readonly raDeg: number | null;
  readonly decDeg: number | null;
  /** Separation from the requested coordinates, arcsec. */
  readonly sepArcsec: number | null;
  readonly instrument: string;
  readonly fpu: string;
  readonly disperser: string;
  readonly wavelengthUm: number | null;
  readonly filter: string;
}

/** Angular separation between two sky positions, arcsec (haversine — exact at
 *  the arcsecond scales these cone searches produce). */
export function separationArcsec(ra1Deg: number, dec1Deg: number, ra2Deg: number, dec2Deg: number): number {
  const rad = Math.PI / 180;
  const dRa = (ra2Deg - ra1Deg) * rad;
  const dDec = (dec2Deg - dec1Deg) * rad;
  const a = Math.sin(dDec / 2) ** 2 + Math.cos(dec1Deg * rad) * Math.cos(dec2Deg * rad) * Math.sin(dRa / 2) ** 2;
  return 2 * Math.asin(Math.min(1, Math.sqrt(a))) * (1 / rad) * 3600;
}

/** Aggregate jsonsummary files into one row per observation_id, with file (#)
 *  and QA-Pass (P) counts and the first file's representative configuration. */
export function aggregateDuplicates(
  sourceId: string,
  raDeg: number,
  decDeg: number,
  files: readonly ArchiveFile[],
): DuplicateRow[] {
  const byObservation = new Map<string, ArchiveFile[]>();
  for (const f of files) {
    if (!f.observation_id) continue;
    const group = byObservation.get(f.observation_id);
    if (group) group.push(f);
    else byObservation.set(f.observation_id, [f]);
  }
  return Array.from(byObservation.entries()).map(([observationId, group]) => {
    const first = group[0]!;
    return {
      key: `${sourceId}:${observationId}`,
      sourceId,
      observationId,
      passCount: group.filter((f) => f.qa_state === 'Pass').length,
      fileCount: group.length,
      target: first.object ?? '—',
      raDeg: first.ra,
      decDeg: first.dec,
      sepArcsec: first.ra !== null && first.dec !== null ? separationArcsec(raDeg, decDeg, first.ra, first.dec) : null,
      instrument: first.instrument ?? '—',
      fpu: first.focal_plane_mask ?? '—',
      disperser: first.disperser ?? '—',
      wavelengthUm: first.central_wavelength,
      filter: first.filter_name ?? '—',
    };
  });
}

/** A requested observation / change request to check for duplicates. */
export interface DuplicateSource {
  readonly id: string;
  readonly raDeg: number | null;
  readonly decDeg: number | null;
  /** ODB ObservingModeType, e.g. GMOS_SOUTH_LONG_SLIT. */
  readonly modeType: string | null;
}

// jsonsummary responses are immutable for a given URL within a session;
// cache them so re-selecting a row doesn't refetch. Bounded LRU: a long
// review session over many selections must not accumulate responses forever.
const RESPONSE_CACHE_LIMIT = 50;
const responseCache = new Map<string, readonly ArchiveFile[]>();

async function fetchArchive(url: string, signal: AbortSignal): Promise<readonly ArchiveFile[]> {
  const cached = responseCache.get(url);
  if (cached) {
    // Refresh recency: Map iterates in insertion order, so re-inserting
    // moves this entry to the back (most recently used).
    responseCache.delete(url);
    responseCache.set(url, cached);
    return cached;
  }
  const res = await fetch(url, { signal });
  if (!res.ok) throw new Error(`Archive query failed: HTTP ${res.status}`);
  const files = (await res.json()) as ArchiveFile[];
  responseCache.set(url, files);
  if (responseCache.size > RESPONSE_CACHE_LIMIT) {
    // Evict the least recently used entry (the front of the Map).
    const oldest = responseCache.keys().next().value;
    if (oldest !== undefined) responseCache.delete(oldest);
  }
  return files;
}

/** Run the duplication check for the given sources. Sources without sidereal
 *  coordinates or a searchable mode are skipped (ToO configurations carry no
 *  coordinates; VISITOR modes have no archive instrument). */
export async function findDuplicates(
  sources: readonly DuplicateSource[],
  signal: AbortSignal,
): Promise<DuplicateRow[]> {
  const searches = sources.flatMap((s) => {
    const sp = archiveSearchSpec(s.modeType);
    if (!sp || s.raDeg === null || s.decDeg === null) return [];
    const { raDeg, decDeg } = s;
    return sp.instruments.map(async (instrument) => {
      const files = await fetchArchive(archiveQueryUrl(instrument, sp.mode, raDeg, decDeg, sp.radiusArcsec), signal);
      return aggregateDuplicates(s.id, raDeg, decDeg, files);
    });
  });
  const rows = (await Promise.all(searches)).flat();
  return rows.sort(
    (a, b) => a.sourceId.localeCompare(b.sourceId) || (a.sepArcsec ?? Infinity) - (b.sepArcsec ?? Infinity),
  );
}

