    expect(c?.programId).toBe('p-172');
    expect(c?.programReference).toBe('G-2027B-0172-Q');
    expect(c?.pi).toBe('Andrew Stephens');
    expect(c?.site).toBe('SOUTH');
    expect(c?.instrument).toBe('GMOS-S');
    expect(c?.ra).toBe('06:08:31.926560');
