                  dec: { __typename: 'Declination', dms: '+41:14:37', degrees: 41.243611 },
                },
              },
            },
          },
        ],
      },
    });
    expect(out.get('o-9c5')).toEqual({
      id: 'o-9c5',
      target: 'Bol 213',
      ra: '00:41:24',
      dec: '+41:14:37',
      raDeg: 10.35,
      decDeg: 41.243611,
